1	const countNeighbors = (cell: number[], livingCells: number[][]): number => {
2	  const [x, y] = cell;
3	  return livingCells.filter(
4	    ([cx, cy]) =>
5	      Math.abs(cx - x) <= 1 &&
6	      Math.abs(cy - y) <= 1 &&
7	      !(cx === x && cy === y)
8	  ).length;
9	};
10	
11	export const nextGeneration = (livingCells: number[][]): number[][] => {
12	  return livingCells.filter(
13	    (cell) => {
14	      const neighborCount = countNeighbors(cell, livingCells);
15	      return neighborCount === 2 || neighborCount === 3;
16	    }
17	  );
18	};
